[217] يُنظر: ((تفسير ابن جرير)) (10/114)، ((تفسير البغوي)) (2/185)، ((تفسير السعدي)) (ص: 285). قال ابن عباس: (بيِّنُ العداوةِ؛ حيث أبى السُّجودَ، وقال: لَأَقْعُدَنَّ لَهُمْ صِرَاطَكَ الْمُسْتَقِيمَ
[الأعراف:16]
). ((البسيط)) للواحدي (9/72).

[651] يُنظر: ((تفسير ابن جرير)) (10/245)، ((تفسير ابن كثير)) (3/426)، ((العذب النمير)) للشنقيطي (3/343). قال ابنُ كثير: (الستَّةُ الأيَّامِ هي: الأحد، والاثنين، والثلاثاء، والأربعاء، والخميس، والجمعة). ((تفسير ابن كثير)) (3/426). وقال الشنقيطي: (العلماء يقولون: إنَّ هذه الأيَّامَ، المرادُ بها أوقاتُها؛ لأنَّه في ذلك الوقتِ لم يكُنْ هنالك يومٌ؛ لأنَّ اليومَ مِن طُلوعِ الشَّمسِ إلى غُروبِها، وإن لم يكن هنالك شَمسٌ لا يُعرَفُ اليومُ إلَّا أنَّ اللهَ قبل أن يخلُقَ الشَّمسَ والقَمَرَ، يعلم زمَنَ الأيَّامِ قبل وجودِ الشَّمسِ.. وهذه الأيامُ قال بعضُ العلماء: إنَّها كأيَّامِ الدُّنيا. وقال بعضُهم: اليومُ منها هو المذكورُ في قوله: وَإِنَّ يَوْمًا عِنْدَ رَبِّكَ كَأَلْفِ سَنَةٍ مِمَّا تَعُدُّونَ
[الحج: 47]
). ((العذب النمير)) (3/344-  345). وقال ابنُ عاشور: (وظاهِرُ الآياتِ أنَّ الأيَّامَ هي المعروفةُ للنَّاسِ.. وقد قيل: إنَّ الأيَّامَ هنا جمعُ اليومِ مِن أيَّامِ الله تعالى، الذي هو مُدَّةُ ألفِ سَنةٍ، فسِتَّةُ أيَّامٍ عبارةٌ عن ستَّةِ آلافٍ مِنَ السِّنينَ). ((تفسير ابن عاشور)) (8-ب/162).

[1275] يُنظر: ((تفسير البغوي)) (2/218)، ((تفسير ابن كثير)) (3/454)، ((تفسير السعدي)) (ص: 299). قال ابن عاشور: (الظَّاهرُ أنَّ خِطابَ موسى فرعونَ بقوله: يَا فِرْعَوْنُ خطابُ إكرامٍ؛ لأنَّه ناداه بالاسمِ الدَّالِّ على المُلكِ والسُّلطانِ بحسَبِ مُتعارَفِ أُمَّتِه، فليس هو بترفُّعٍ عليه؛ لأنَّ اللهَ تعالى قال له ولهارونَ: فَقُولَا لَهُ قَوْلًا لَيِّنًا
[طه:44]
). ((تفسير ابن عاشور)) (9/37).

[1423] قال الشنقيطي: (وقراءةُ الجمهورِ: وَآلِهَتَكَ، ويذرك فلا يَعْبُدك، ويَذر آلهتَك فلا يعبدها، وقراءةُ ابنِ عبَّاسٍ: «وَيَذَرَكَ وإِلَاهَتَكَ»، أي: وعِبادتَكَ، وهي قراءةٌ شاذَّةٌ). ((العذب النمير)) (4/99). قال ابن عاشور: (كان القِبطُ مُشرِكين يَعبدون آلهةً متنوِّعةً من الكواكبِ والعناصرِ، وصوَّروا لها صورًا عديدةً مختلِفةً باختلافِ العصورِ والأقطارِ... وكان أعظمُ هذه الأصنامِ هو الَّذي يَنتسِب فرعونُ إلى بُنُوَّتِه وخِدْمتِه، وكان فرعونُ معدودًا ابنَ الآلهةِ، وقد حلَّتْ فيه الإلهيَّةُ على نحوِ عقيدةِ الحُلولِ، ففرعونُ هو المنفِّذُ للدِّينِ، وكان يُعَدُّ إلهَ مصرَ، وكانت طاعتُه طاعةً للآلهةِ كما حَكَى اللهُ تعالى عنه: فَقَالَ أَنَا رَبُّكُمُ الْأَعْلَى [النازعات: 24]، مَا عَلِمْتُ لَكُمْ مِنْ إِلَهٍ غَيْرِي
[القصص: 38]
). ((تفسير ابن عاشور)) (9/58- 59).

[1564] قرأ بها ابن عامر. يُنظر: ((النشر)) لابن الجزري (2/271). وهذا المعنى هو اختيارُ ابن خالويه، وظاهرُ اختيار مكيٍّ، واختاره أبو حيان. قال ابن خالويه: (وَإِذْ أَنْجَيْنَاكُمْ يُقرأ بإثبات الياء والنون وبحذفهما... والحُجَّة لمَنْ حذفها: أنَّه من إخبار النَّبيِّ عليه السَّلامُ عن الله، والفاعل مُستتِرٌ في الفعل، و(إذ) في أوَّلِ الكلام متعلِّقةٌ بفِعْلٍ دليلُه قوله تعالى: وَاذْكُرُوا إِذْ أَنْتُمْ قَلِيلٌ
[الأنفال: 26]
). ((الحجة في القراءات السبع)) (ص: 162- 163). ويُنظر: ((الكشف)) لمكي (1/475)، ((تفسير أبي حيان)) (5/159). وذَهب الأزهريُّ إلى أنَّها إخبارٌ من الله تعالى عن نفْسِه؛ فمعنى القراءتين لديه واحدٌ، حيثُ قال: (ومعنى أنجيناكم وأنجاكم واحدٌ؛ لأنَّ الإنجاءَ لله جلَّ وعزَّ). ((معاني القراءات)) (1/422).

[1744] يُنظر: ((تفسير ابن جرير)) (10/451، 454)، ((تفسير ابن كثير)) (3/477)، ((تفسير السعدي)) (ص: 303)، ((تفسير ابن عاشور)) (9/115). قال الرازيُّ: (ليس في القرآن إلَّا أنَّه أَلْقى الألواحَ، فأمَّا أنَّه ألْقاها بحيثُ تَكسَّرَتْ فهذا ليس في القُرآن). ((تفسير الرازي)) (15/372). وقال ابنُ عاشور: (وقَعَ في التَّوراةِ أنَّ الألواحَ تكسَّرَتْ حين ألقاها، وليس في القرآنِ ما يدُلُّ على ذلك سِوى أنَّ التعبيرَ بالإلقاء الذي هو الرَّمْيُ، وما رُوِيَ من أنَّ الألواح كانت من حَجَرٍ، يقتضي أنها اعتراها انكسارٌ، ولكنَّ ذلك الانكسارَ لا يُذهب ما احتوتْ عليه من الكتابة، وأمَّا ما رُوِيَ أنها لمَّا تكسَّرت ذهب سِتَّةُ أسباعِها، أو ذهب تفصيلُها وبَقِيَتْ موعظتُها، فهو مِن وَضْعِ القصَّاصين، والله تعالى يقول: وَلَمَّا سَكَتَ عَنْ مُوسَى الْغَضَبُ أَخَذَ الْأَلْوَاحَ وَفِي نُسْخَتِهَا هُدًى وَرَحْمَةٌ لِلَّذِينَ هُمْ لِرَبِّهِمْ يَرْهَبُونَ
[الأعراف: 154]
). ((تفسير ابن عاشور)) (9/115- 116). وقال الشنقيطيُّ: (وكثيرٌ من المفسِّرين يقولون: إنَّه ألقاها إلقاءً قويًّا حتى تكسَّرت، وأنه رُفِعَ شيءٌ منها مع المكسَّرِ منها. وكلُّ هذا لا دليلَ عليه، ولم يَقُمْ عليه دليلٌ صحيحٌ لا في كتاب ولا من سُنَّةٍ، وظاهرُ القرآنِ أنَّها لم تتكسَّرْ، ولم يَضِعْ منها شيء؛ لأنه قال: وَلَمَّا سَكَتَ عَن مُّوسَى الْغَضَبُ أَخَذَ الأَلْوَاحَ [الأعراف: آية 154]، و(أل) هنا عَهْدِيَّةٌ، وهي الألواح المعهودةُ التي ألقاها). ((العذب النمير)) (4/181- 182).

[2081] وممَّن اختار هذا القولَ: ابنُ جريرٍ، والواحديُّ، والقرطبي، والشوكاني، والشنقيطي. يُنظَر: ((تفسير ابن جرير)) (10/546، 552- 561)، ((الوجيز)) للواحدي (ص: 420)، ((تفسير القرطبي)) (7/314)، ((تفسير الشوكاني)) (2/299)، ((العذب النمير)) للشنقيطي (4/310)، ((أضواء البيان)) للشنقيطي (2/43). قال ابنُ جُزيٍّ: (في معناها قولان: أحدُهما: أنَّ اللهَ لَمَّا خلق آدمَ أخرَجَ ذريَّتَه من صُلبِه، وهم مِثلُ الذَّرِّ، وأخذ عليهم العَهدَ بأنَّه ربُّهم، فأقرُّوا بذلك والتَزَموه؛ رُوِيَ هذا المعنى عن النبيِّ- صلَّى اللهُ تعالى عليه وآلِه وسلَّم- مِن طُرُقٍ كثيرةٍ، وقال به جماعةٌ من الصحابةِ وغَيرِهم. والثاني: أنَّ ذلك من بابِ التَّمثيلِ، والأول هو الصَّحيحُ؛ لتواتُرِ الأخبارِ به، إلَّا أنَّ ألفاظَ الآيةِ لا تُطابِقُه بظاهِرِها، فلذلك عَدَلَ عنه من قال بالقَولِ الآخَرِ، وإنَّما تُطابِقُه بتأويلٍ: وذلك أنَّ أخْذَ الذرِّيَّة إنَّما كان مِن صُلبِ آدَمَ، ولفظُ الآية يقتضي أنَّ أخْذَ الذرِّيَّة من بني آدَمَ، والجمعُ بينهما أنَّه ذَكَرَ بني آدَمَ في الآيةِ، والمرادُ آدَمُ؛ كقوله: وَلَقَدْ خَلَقْنَاكُمْ ثُمَّ صَوَّرْنَاكُمْ
[الأعراف: 11]
). ((تفسير ابن جزي)) (1/312). ويُنظَر: ((معاني القرآن)) للزجاج (2/390). وقال الشوكاني: (وقيل: المرادُ ببني آدَمَ هنا: آدمُ نَفسُه؛ كما وقع في غَيرِ هذا الموضِعِ. والمعنى: أنَّ الله سُبحانه لَمَّا خلَقَ آدمَ مَسحَ ظَهرَه فاستخرجَ منه ذرِّيَّتَه، وأخذ عليهم العَهدَ، وهؤلاء هم عالَمُ الذَّرِّ، وهذا هو الحقُّ الذي لا ينبغي العدولُ عنه، ولا المصيرُ إلى غيره؛ لثبوته مرفوعًا إلى النبيِّ صلَّى اللهُ عليه وسلَّم، وموقوفًا على غيرِه من الصَّحابة، ولا مُلجِئَ للمصيرِ إلى المجازِ، وإذا جاء نَهرُ اللهِ بطَلَ نَهرُ مَعقِل). ((تفسير الشوكاني)) (2/299). وقال ابنُ عبد البر: (ومعنى الآيةِ والحديثِ: أنَّه أخرج ذرِّيَّةَ آدم مِن ظَهرِه كيف شاء ذلك، وألهَمَهم أنَّه ربُّهم، فقالوا: بلى؛ لِئلَّا يقولوا يومَ القيامةِ إنَّا كنَّا عن هذا غافلينَ، ثم تابَعَهم بحجَّةِ العَقلِ عند التَّمييزِ، وبالرُّسُلِ بعد ذلك؛ استظهارًا بما في عقولِهم من المنازعةِ إلى خالِقٍ مُدَبِّرٍ حكيمٍ، يُدَبِّرُهم بما لا يتهيَّأُ لهم، ولا يُمكِنُهم جَحدُه، وهذا إجماعُ أهلِ السُّنَّة، والحمد لله). ((التمهيد)) (18/89، 95، 96). وقيل: أي: خَلَقَهم حين وُلِدوا على الفِطرةِ مُقِرِّينَ بأنَّ اللهَ رَبُّهم، ففِطَرُهم شاهدةٌ عليه، ويكونُ سبحانه بذلك قد أشهَدَهم على أنفُسِهم وقرَّرَهم، وممَّن اختار هذا القولَ: ابنُ تيميَّةَ، وابنُ القيِّم، وابنُ كثيرٍ، والقاسميُّ، والسعديُّ. يُنظَر: ((جامع الرسائل لابن تيمية)) (1/11، 12)، ((درء تعارض العقل والنقل)) لابن تيمية (8/482 - 491)،  ((الروح)) لابن القيم (ص: 163-171)، ((أحكام أهل الذمة)) لابن القيم (2/948)، ((تفسير ابن كثير)) (3/500)، ((تفسير القاسمي)) (5/217)، ((تفسير السعدي)) (ص: 308).

